// Get all articles sorted by date (newest first)
export function getAllArticles(): BlogArticle[] {
  return [...BLOG_ARTICLES].sort((a, b) =>
    new Date(b.published_at).getTime() - new Date(a.published_at).getTime()
  )
}

// Get single article by slug
export function getArticleBySlug(slug: string): BlogArticle | undefined {
  return BLOG_ARTICLES.find(a => a.slug === slug)
}

// Get related articles (same category or overlapping tags)
export function getRelatedArticles(article: BlogArticle, limit = 3): BlogArticle[] {
  return BLOG_ARTICLES
    .filter(a => a.slug !== article.slug)
    .map(a => ({
      article: a,
      score:
        (a.category === article.category ? 2 : 0) +
        a.tags.filter(t => article.tags.includes(t)).length,
    }))
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map(a => a.article)
}

// Get all unique categories
export function getArticleCategories(): string[] {
  return [...new Set(BLOG_ARTICLES.map(a => a.category))]
}

